#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    if (N < 1 || N > 100) {
        // Handle invalid N if necessary, though problem states 1 <= N <= 100
        return 1;
    }

    int arr[100]; // Max size 100 as per constraints
    int sum_positive = 0;
    int count_positive = 0;

    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
        if (arr[i] > 0) {
            sum_positive += arr[i];
            count_positive++;
        }
    }

    printf("Sum: %d\n", sum_positive);
    printf("Count: %d\n", count_positive);

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h> // For tolower()

int main() {
    char line[256]; // 255 characters + null terminator

    // Read a line from stdin
    if (fgets(line, sizeof(line), stdin) == NULL) {
        return 1; // Error reading input
    }

    // Remove trailing newline character if it exists
    size_t len = strlen(line);
    if (len > 0 && line[len - 1] == '\n') {
        line[len - 1] = '\0';
        len--; // Adjust length
    }

    int vowel_count = 0;
    for (size_t i = 0; i < len; i++) {
        char c = tolower(line[i]); // Convert to lowercase for case-insensitive check
        if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
            vowel_count++;
        }
    }

    printf("Length: %zu\n", len);
    printf("Vowels: %d\n", vowel_count);

    return 0;
}

#include <stdio.h>

int main() {
