#include <stdio.h>
#include <string.h>
#include <ctype.h> // For isalnum() and tolower()

int main() {
    char line[256];
    if (fgets(line, sizeof(line), stdin) == NULL) {
        return 1;
    }

    // Remove trailing newline if present
    size_t len = strlen(line);
    if (len > 0 && line[len - 1] == '\n') {
        line[len - 1] = '\0';
        len--;
    }

    char cleaned_str[256];
    int cleaned_idx = 0;

    // Filter for alphanumeric characters and convert to lowercase
    for (size_t i = 0; i < len; i++) {
        if (isalnum(line[i])) {
            cleaned_str[cleaned_idx++] = tolower(line[i]);
        }
    }
    cleaned_str[cleaned_idx] = '\0'; // Null-terminate the cleaned string

    // Check if the cleaned string is a palindrome
    int is_palindrome = 1;
    int left = 0;
    int right = cleaned_idx - 1;

    while (left < right) {
        if (cleaned_str[left] != cleaned_str[right]) {
            is_palindrome = 0;
            break;
        }
        left++;
        right--;
    }

    if (is_palindrome) {
        printf("Is a palindrome.\n");
    } else {
        printf("Is not a palindrome.\n");
    }

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    if (N < 1 || N > 100) {
        return 1; // Invalid N
    }

    int arr[100]; // Max size 100
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }

    // In-place reversal using two pointers
    int left = 0;
    int right = N - 1;
    while (left < right) {
        // Swap elements
        int temp = arr[left];
        arr[left] = arr[right];
        arr[right] = temp;

        left++;
        right--;
    }

    // Print the reversed array
    for (int i = 0; i < N; i++) {
        printf("%d", arr[i]);
        if (i < N - 1) {
            printf(" ");
        }
    }
    printf("\n");

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <stdlib.h> // For strtok_r

int main() {
    char line[256];
    char smallest_word[31] = "";
    char largest_word[31] = "";
    int min_len = 257; // Larger than max possible word length (30)
    int max_len = 0;

    if (fgets(line, sizeof(line), stdin) == NULL) {
        return 1;
    }

    // Remove trailing newline if present
    size_t len = strlen(line);
    if (len > 0 && line[len - 1] == '\n') {
        line[len - 1] = '\0';
    }

    char *token;
    char *rest = line; // Pointer for strtok_r to handle context

    // strtok_r is reentrant and safer than strtok in multi-threaded contexts, but also works in single-threaded
    // for this exercise, strtok could also be used for simplicity, but strtok_r is good practice.
    token = strtok_r(rest, " ", &rest); 

    if (token == NULL) { // No words found or empty line
        printf("No words found.\n");
        return 0;
    }

    while (token != NULL) {
        int current_len = strlen(token);

        if (current_len < min_len) {
            min_len = current_len;
            strcpy(smallest_word, token);
        }
        if (current_len > max_len) {
            max_len = current_len;
            strcpy(largest_word, token);
        }
        token = strtok_r(NULL, " ", &rest);
    }

    if (strlen(smallest_word) > 0) { // Check if any words were processed
        printf("Smallest: %s\n", smallest_word);
        printf("Largest: %s\n", largest_word);
    } else {
        printf("No words found.\n"); // Fallback for edge cases like only spaces
    }

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h> // For tolower() and isalpha()

int main() {
    char line[256];
    int counts[26] = {0}; // Array to store counts for 'a' through 'z'

    if (fgets(line, sizeof(line), stdin) == NULL) {
        return 1;
    }

    // Remove trailing newline if present
    size_t len = strlen(line);
    if (len > 0 && line[len - 1] == '\n') {
        line[len - 1] = '\0';
    }

    for (size_t i = 0; i < len; i++) {
        if (isalpha(line[i])) { // Check if it's an alphabet character
            char c = tolower(line[i]); // Convert to lowercase
            counts[c - 'a']++; // Increment count for the corresponding letter
        }
    }

    // Print character counts in alphabetical order
    for (int i = 0; i < 26; i++) {
        if (counts[i] > 0) {
            printf("%c:%d\n", (char)('a' + i), counts[i]);
        }
    }

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    scanf("%d", &N);

    if (N < 1 || N > 100) {
        return 1; // Invalid N
    }

    int arr[100]; // Max size 100
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }

    if (N == 0) { // Although N >= 1, good to handle
        printf("\n");
        return 0;
    }

    int unique_idx = 0;
    // Iterate through the array
    for (int i = 0; i < N; i++) {
        // If the current element is different from the last unique element found
        // (or if it's the first element), then it's a new unique element.
        if (i == 0 || arr[i] != arr[i-1]) {
            arr[unique_idx] = arr[i]; // Store it at the next unique position
            unique_idx++;
        }
    }

    // Print the unique elements
    for (int i = 0; i < unique_idx; i++) {
        printf("%d", arr[i]);
        if (i < unique_idx - 1) {
            printf(" ");
        }
    }
    printf("\n");

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h> // For isalpha(), isupper(), tolower()

int main() {
    char line[256];
    int shift;

    if (fgets(line, sizeof(line), stdin) == NULL) {
        return 1;
    }
    scanf("%d", &shift);

    // Remove trailing newline from line if present
    size_t len = strlen(line);
    if (len > 0 && line[len - 1] == '\n') {
        line[len - 1] = '\0';
    }

    // Normalize shift to be between 0 and 25
    shift = shift % 26;
    if (shift < 0) {
        shift += 26; // Ensure positive shift
    }

    for (size_t i = 0; i < len; i++) {
        if (isalpha(line[i])) {
            char base;
            if (isupper(line[i])) {
                base = 'A';
            } else {
                base = 'a';
            }
            // Apply shift
            line[i] = base + (line[i] - base + shift) % 26;
        }
    }

    printf("%s\n", line);

    return 0;
}

#include <stdio.h>

int main() {
    int R, C;
    scanf("%d %d", &R, &C);

    if (R < 1 || R > 10 || C < 1 || C > 10) {
        return 1; // Invalid R or C
    }

    int matrix[10][10]; // Max size 10x10

    // Read matrix elements
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            scanf("%d", &matrix[i][j]);
        }
    }

    // Calculate and print row sums
    for (int i = 0; i < R; i++) {
        int row_sum = 0;
        for (int j = 0; j < C; j++) {
            row_sum += matrix[i][j];
        }
        printf("Row %d Sum: %d\n", i, row_sum);
    }

    return 0;
}
